      out.write("\n");
      out.write("const months = [\"January\",\"February\",\"March\",\"April\",\"May\",\"June\",\"July\",\"August\",\"September\",\"October\",\"November\",\"December\"];\n");
      out.write("\n");
      out.write("function pad(n) { return n.toString().padStart(2,'0'); }\n");
      out.write("function formatDate(d) { return d.getFullYear() + \"-\" + pad(d.getMonth()+1) + \"-\" + pad(d.getDate()); }\n");
      out.write("\n");
      out.write("function loadCalendar() {\n");
      out.write("  document.getElementById(\"monthYear\").textContent = months[currentMonth] + \" \" + currentYear;\n");
      out.write("  fetch(\"getHolidays?t=\" + Date.now())\n");
      out.write("    .then(r => r.json())\n");
      out.write("    .then(holidays => {\n");
      out.write("      holidayMap = {};\n");
      out.write("      holidays.forEach(h => { holidayMap[h.date] = { name: h.name }; });\n");
      out.write("      renderCalendar();\n");
