      out.write("    .catch(() => renderCalendar());\n");
      out.write("}\n");
      out.write("\n");
      out.write("function renderCalendar() {\n");
      out.write("  const tbody = document.getElementById(\"calBody\");\n");
      out.write("  tbody.innerHTML = \"\";\n");
      out.write("  const firstDay = new Date(currentYear, currentMonth, 1).getDay();\n");
      out.write("  const daysInMonth = new Date(currentYear, currentMonth + 1, 0).getDate();\n");
      out.write("  const todayStr = formatDate(today);\n");
      out.write("\n");
      out.write("  let row = document.createElement(\"tr\");\n");
      out.write("  for (let i = 0; i < firstDay; i++) {\n");
      out.write("    const cell = document.createElement(\"td\");\n");
      out.write("    cell.className = \"cal-day other-month border border-slate-200\";\n");
      out.write("    const prevMonth = currentMonth === 0 ? 11 : currentMonth - 1;\n");
      out.write("    const prevYear = currentMonth === 0 ? currentYear - 1 : currentYear;\n");
      out.write("    const prevDays = new Date(prevYear, prevMonth + 1, 0).getDate();\n");
      out.write("    cell.innerHTML = prevDays - firstDay + i + 1;\n");
      out.write("    row.appendChild(cell);\n");
      out.write("  }\n");
      out.write("\n");
      out.write("  for (let d = 1; d <= daysInMonth; d++) {\n");
      out.write("    if (row.children.length === 7) {\n");
      out.write("      tbody.appendChild(row);\n");
      out.write("      row = document.createElement(\"tr\");\n");
      out.write("    }\n");
      out.write("    const fullDate = currentYear + \"-\" + pad(currentMonth + 1) + \"-\" + pad(d);\n");
      out.write("    const cell = document.createElement(\"td\");\n");
      out.write("    cell.className = \"cal-day border border-slate-200 text-center text-slate-800\";\n");
      out.write("    const isHoliday = holidayMap[fullDate];\n");
      out.write("    const isToday = fullDate === todayStr;\n");
      out.write("\n");
      out.write("    if (isHoliday) {\n");
      out.write("      cell.classList.add(\"holiday-blocked\");\n");
      out.write("      cell.innerHTML = \"<div class=\\\"font-semibold\\\">\" + d + \"</div><div class=\\\"text-xs mt-1 truncate\\\" title=\\\"\" + (isHoliday.name || \"\") + \"\\\">\" + (isHoliday.name || \"Holiday\") + \"</div>\";\n");
      out.write("    } else {\n");
      out.write("      cell.innerHTML = \"<div class=\\\"font-medium\\\">\" + d + \"</div>\";\n");
      out.write("    }\n");
      out.write("    if (isToday) cell.classList.add(\"today\");\n");
      out.write("    if (");
      out.print( isAdmin );
      out.write(") {\n");
      out.write("      cell.style.cursor = \"pointer\";\n");
      out.write("      cell.onclick = () => openForDate(fullDate);\n");
      out.write("    }\n");
      out.write("    row.appendChild(cell);\n");
      out.write("  }\n");
      out.write("\n");
      out.write("  const remaining = 7 - row.children.length;\n");
      out.write("  if (remaining < 7) {\n");
      out.write("    for (let i = 0; i < remaining; i++) {\n");
      out.write("      const cell = document.createElement(\"td\");\n");
      out.write("      cell.className = \"cal-day other-month border border-slate-200\";\n");
      out.write("      cell.innerHTML = i + 1;\n");
      out.write("      row.appendChild(cell);\n");
      out.write("    }\n");
      out.write("  }\n");
      out.write("  tbody.appendChild(row);\n");
      out.write("}\n");
      out.write("\n");
      out.write("function changeMonth(step) {\n");
      out.write("  currentMonth += step;\n");
      out.write("  if (currentMonth < 0) { currentMonth = 11; currentYear--; }\n");
      out.write("  if (currentMonth > 11) { currentMonth = 0; currentYear++; }\n");
      out.write("  loadCalendar();\n");
      out.write("}\n");
      out.write("\n");
      out.write("function goToday() {\n");
      out.write("  currentMonth = today.getMonth();\n");
