      out.write("}\n");
      out.write("\n");
      out.write("function openForDate(dateStr) {\n");
      out.write("  const todayStr = formatDate(new Date());\n");
      out.write("  if (dateStr < todayStr) {\n");
      out.write("    showToast(\"Cannot add holiday for past date\", \"error\");\n");
      out.write("    return;\n");
      out.write("  }\n");
      out.write("  fetch(\"getHolidayByDate?date=\" + dateStr)\n");
      out.write("    .then(r => r.json())\n");
      out.write("    .then(data => {\n");
      out.write("      editMode = data.exists;\n");
      out.write("      selectedDate = dateStr;\n");
      out.write("      document.getElementById(\"modalTitle\").textContent = editMode ? \"Edit Holiday\" : \"Add New Holiday\";\n");
      out.write("      document.getElementById(\"holidayDate\").value = dateStr;\n");
      out.write("      document.getElementById(\"holidayDate\").disabled = editMode;\n");
      out.write("      document.getElementById(\"holidayName\").value = data.name || \"\";\n");
      out.write("      document.getElementById(\"holidayType\").value = \"Public\";\n");
      out.write("      document.getElementById(\"deleteBtn\").style.display = editMode ? \"block\" : \"none\";\n");
      out.write("      document.getElementById(\"holidayModal\").classList.remove(\"hidden\");\n");
      out.write("      document.getElementById(\"holidayModal\").classList.add(\"flex\");\n");
      out.write("    });\n");
      out.write("}\n");
      out.write("\n");
      out.write("function closeModal() {\n");
      out.write("  document.getElementById(\"holidayModal\").classList.add(\"hidden\");\n");
      out.write("  document.getElementById(\"holidayModal\").classList.remove(\"flex\");\n");
      out.write("}\n");
      out.write("\n");
      out.write("function saveHoliday(ev) {\n");
      out.write("  ev.preventDefault();\n");
      out.write("  const date = document.getElementById(\"holidayDate\").value;\n");
      out.write("  const name = document.getElementById(\"holidayName\").value.trim();\n");
      out.write("  if (!name) { showToast(\"Enter holiday name\", \"error\"); return; }\n");
      out.write("  const todayStr = formatDate(new Date());\n");
      out.write("  if (date < todayStr) { showToast(\"Cannot add holiday for past date\", \"error\"); return; }\n");
      out.write("  const url = editMode ? \"updateHoliday\" : \"addHoliday\";\n");
      out.write("  const body = editMode\n");
      out.write("    ? \"date=\" + encodeURIComponent(selectedDate) + \"&name=\" + encodeURIComponent(name)\n");
      out.write("    : \"date=\" + encodeURIComponent(date) + \"&name=\" + encodeURIComponent(name);\n");
      out.write("  fetch(url, {\n");
      out.write("    method: \"POST\",\n");
      out.write("    headers: { \"Content-Type\": \"application/x-www-form-urlencoded\" },\n");
      out.write("    body: body\n");
      out.write("  })\n");
      out.write("    .then(r => r.text())\n");
      out.write("    .then(msg => {\n");
      out.write("      showToast(msg || \"Saved\");\n");
      out.write("      closeModal();\n");
      out.write("      loadCalendar();\n");
      out.write("      loadUpcoming();\n");
      out.write("    })\n");
      out.write("    .catch(() => showToast(\"Operation failed\", \"error\"));\n");
      out.write("}\n");
      out.write("\n");
      out.write("function deleteHoliday() {\n");
      out.write("  if (!confirm(\"Delete this holiday?\")) return;\n");
      out.write("  fetch(\"deleteHoliday?date=\" + encodeURIComponent(selectedDate))\n");
      out.write("    .then(r => r.text())\n");
      out.write("    .then(msg => {\n");
      out.write("      showToast(msg || \"Deleted\");\n");
      out.write("      closeModal();\n");
      out.write("      loadCalendar();\n");
      out.write("      loadUpcoming();\n");
      out.write("    })\n");
